window.__QUIZ_DATA__=[{"id":"objective>Biology>2021>1","subject":"Biology","year":"2021","type":"Objective","topic":"CONCEPT OF LIVING : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS.","question":"Which of the following organelles is common to both plant and animal cells?","images":[],"options":{"A":"cellulose cell wall","B":"Chlorophyll","C":"cell membrane","D":"large vacuole"},"answer":"C","explanation":"Both plant and animal cells have a cell membrane. The cell membrane, also known as the plasma membrane, is a biological membrane that separates the interior of all cells from the outside environment. It provides protection and also allows the passage of ions and organic molecules in and out of the cell.","marks":"1","difficulty":"1"},{"id":"objective>Biology>2021>2","subject":"Biology","year":"2021","type":"Objective","topic":"CONCEPT OF LIVING : REPRODUCTION","question":"The diagram below illustrate different sections of  a particular fruit, study the diagram and answer the question      The section in X and Y respectively, are","images":["data:image/jpeg;base64,"],"options":{"A":"longitudinal and transverse","B":"transverse and longitudinal","C":"cross and transverse","D":"transverse and cross"},"answer":"B","explanation":"A transverse section (or cross-section) and a longitudinal section refer to different ways of cutting or viewing an object, typically in biological contexts.  Transverse Section:    Direction: Cut across the short axis.    Example: Cutting a tree trunk into round slices.    View: Cross-section (circular shape).  Longitudinal Section:    Direction: Cut along the long axis.    Example: Cutting a tree trunk lengthwise.    View: Lengthwise section (long shape).","marks":"1","difficulty":"2"},{"id":"objective>Biology>2021>3","subject":"Biology","year":"2021","type":"Objective","topic":"CONCEPT OF LIVING : REPRODUCTION","question":"The diagram below illustrate different sections of  a particular fruit, study the diagram and answer the question    The fruit that has the illustrated sections is a","images":["data:image/jpeg;base64,"],"options":{"A":"Hesperidium","B":"capsule","C":"drupe","D":"cypsela"},"answer":"A","explanation":"The fruit that has the illustrated sections is a hesperidum (plural : hesperidia) is a modified berry with with a tough, leathery, and a juicing pulp divided into segment  as an orange or other citrus fruit.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2021>4","subject":"Biology","year":"2021","type":"Objective","topic":"MICROORGANISMS: MAN AND HEALTH : MICROORGANISMS IN ACTION","question":"The diagram below is the illustration of a fungus. study it and answer the question      The structure labelled I is associated with","images":["data:image/jpeg;base64,"],"options":{"A":"sexual reproduction","B":"asexual reproduction","C":"bud formation","D":"gamete formation"},"answer":"B","explanation":"The structure labelled I is the sporangium contains  spores which ar used to reproduce fungal cells asexually","marks":"1","difficulty":"2"},{"id":"objective>Biology>2021>5","subject":"Biology","year":"2021","type":"Objective","topic":"MICROORGANISMS: MAN AND HEALTH : MICROORGANISMS IN ACTION","question":"The diagram below is the illustration of a fungus. study it and answer the question    The structure labelled II is the","images":["data:image/jpeg;base64,"],"options":{"A":"Spore","B":"stolon","C":"Columella","D":"sporangium"},"answer":"C","explanation":"The structure labelled II is the columella. It is found at the base of sporangium and it is responsible for its bursting","marks":"1","difficulty":"2"},{"id":"objective>Biology>2021>6","subject":"Biology","year":"2021","type":"Objective","topic":"MICROORGANISMS: MAN AND HEALTH : MICROORGANISMS IN ACTION","question":"The diagram below is the illustration of a fungus. study it and answer the question    Which of the following statement about the structure labelled III is correct ? it","images":["data:image/jpeg;base64,"],"options":{"A":"secretes digestive enzymes into the substrate","B":"absorbs minerals salts from the soil","C":"forms the root hairs of the organism","D":"develops into stolon"},"answer":"A","explanation":"The structure labeled III in the diagram is representing rhizoids, which are root-like structures in fungi. Among the given options, the correct statement about the structure labeled III is: A. secretes digestive enzymes into the substrate. Rhizoids are involved in anchoring the fungus to the substrate and also in nutrient absorption. They secrete digestive enzymes that break down complex organic materials into simpler substances, which can then be absorbed by the fungus.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2021>7","subject":"Biology","year":"2021","type":"Objective","topic":"CONCEPT OF LIVING : ORGANIZATION OF LIFE","question":"The diagram below is an illustration of a living organism .       The level of organisation of the organism is","images":["data:image/jpeg;base64,"],"options":{"A":"tissue","B":"cell","C":"organ","D":"system"},"answer":"B","explanation":"The organism illustrated is euglena. Euglena is unicellular organism, hence it belongs to the cellular level of organization.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2021>8","subject":"Biology","year":"2021","type":"Objective","topic":"CONCEPT OF LIVING : CLASSIFICATION","question":"The diagram below is an illustration of a living organism .     The organism belongs to the phylum","images":["data:image/jpeg;base64,"],"options":{"A":"Rhizopoda","B":"ciliophora","C":"Euglenophyta","D":"Rhodophyta"},"answer":"C","explanation":"Euglena belongs to the phylum Euglenophyta. This group is characterized by organisms that are unicellular, have flagella, and can photosynthesize due to the presence of chloroplasts, although they can also feed heterotrophically.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2021>9","subject":"Biology","year":"2021","type":"Objective","topic":"CONCEPT OF LIVING : THE CELL AND ITS ENVIRONMENT","question":"A plant cell placed in a solution with a higher water potential will","images":[],"options":{"A":"expand and then shrink","B":"enlarge and become turgid","C":"expand and then burst","D":"Decrease in size and become flaccid"},"answer":"B","explanation":"When a plant cell is placed in a solution with a higher water potential , water moves into the cells sap by osmosis(endosmosis) because the cell sap (solution of sugar and salts) in the vacuole is more concentrated . the vacuole increases in Volume (expands) ad distends towards the cytoplasm and cell wall . The cell wall distend(expands) until no further distension , At this point the cell is said to be turgid","marks":"1","difficulty":"2"},{"id":"objective>Biology>2021>10","subject":"Biology","year":"2021","type":"Objective","topic":"BIOLOGY OF HEREDITY (GENETICS) : TRANSMISSION AND EXPRESSION OF CHARACTERISTICS IN ORGANISMS","question":"Offspring formed by sexual reproduction exhibit more variation than those formed by asexual reproduction because","images":[],"options":{"A":"greater amount of DNA is involved in sexual reproduction","B":"gametes of parents have different genetic composition","C":"genetic material come from parents of two different species","D":"sexual reproduction"},"answer":"B","explanation":"sexual reproduction permits variability of individuals which enhances survival in a new environment, This is possible because gametes of parents have different genetic composition.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2021>11","subject":"Biology","year":"2021","type":"Objective","topic":"CONCEPT OF LIVING : TISSUES AND SUPPORTING SYSTEMS","question":"Radius and ulna are bones of the","images":[],"options":{"A":"pectoral girdle","B":"upper arm","C":"pelvic girdle","D":"lower arm"},"answer":"D","explanation":"The radius and ulna are the two long bones located in the forearm (the area between the elbow and the wrist). The radius is on the lateral side (thumb side) and the ulna is on the medial side (little finger side). Therefore, they are not part of the pectoral girdle, upper arm, or pelvic girdle.","marks":"1","difficulty":"1"},{"id":"objective>Biology>2021>12","subject":"Biology","year":"2021","type":"Objective","topic":"CONCEPT OF LIVING : TRANSPORT SYSTEM","question":"The blood vessel which carries blood from the alimentary canal to the liver is the","images":[],"options":{"A":"hepatic artery","B":"hepatic vein","C":"hepatic portal vein","D":"mesenteric artery"},"answer":"C","explanation":"The hepatic portal vein is the blood vessel that carries blood from the alimentary canal to the liver. The alimentary canal is the whole passage along which food passes through the body from mouth to anus. It includes the esophagus, stomach, and intestines. The hepatic portal vein carries nutrient-rich blood from the digestive system to the liver for processing.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2021>13","subject":"Biology","year":"2021","type":"Objective","topic":"CONCEPT OF LIVING : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS.","question":"which of the labelled parts is the cortex?","images":["data:image/jpeg;base64,"],"options":{"A":"I","B":"II","C":"III","D":"IV"},"answer":"D","explanation":"The structure labelled III is the ureter which is a continuation or extension of the pelvis , however , the part labelled IV can be related to the kidney's cortex, although , it is not directly on the cortex, but on the medulla, but this is the closest option to the cortex","marks":"1","difficulty":"2"},{"id":"objective>Biology>2021>14","subject":"Biology","year":"2021","type":"Objective","topic":"CONCEPT OF LIVING : EXCRETORY SYSTEMS","question":"Which is the main function of the organ ?","images":["data:image/jpeg;base64,"],"options":{"A":"excretion","B":"respiration","C":"reproduction","D":"locomotion"},"answer":"A","explanation":"The kidney are organs responsible for the excretion of all nitrogenous wastes  from the body and also responsible for osmoregulation of the blood and body fluid.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2021>15","subject":"Biology","year":"2021","type":"Objective","topic":"CONCEPT OF LIVING : EXCRETORY SYSTEMS","question":"Detoxification of urea takes place in the","images":[],"options":{"A":"pancreas","B":"heart","C":"liver","D":"testes"},"answer":"C","explanation":"The liver is the organ that detoxifies urea. Urea is a waste product formed in the liver. The liver breaks down excess amino acids to form ammonia, which is then converted to a less toxic substance called urea. This urea is then transported by the blood to the kidneys, where it is excreted in urine.","marks":"1","difficulty":"1"},{"id":"objective>Biology>2021>16","subject":"Biology","year":"2021","type":"Objective","topic":"CONCEPT OF LIVING : HORMONAL COORDINATION","question":"Which of the following hormones is suddenly secretes into the bloodstream of the frightened person","images":[],"options":{"A":"insulin","B":"adrenaline","C":"Thyroxine","D":"parathormone"},"answer":"B","explanation":"The hormone that is suddenly secreted into the bloodstream of a frightened person is adrenaline. Adrenaline is a hormone released from the adrenal glands and its major action, together with noradrenaline, is to prepare the body for 'fight or flight'.","marks":"1","difficulty":"1"},{"id":"objective>Biology>2021>17","subject":"Biology","year":"2021","type":"Objective","topic":"CONCEPT OF LIVING : REGULATION OF INTERNAL ENVIRONMENT (HOMEOSTASIS)","question":"The temperature control centre in mammals is located in the","images":[],"options":{"A":"skin","B":"hypothalamus","C":"pituitary gland","D":"adrenal gland"},"answer":"B","explanation":"The temperature control centre in mammals is located in the hypothalamus. The hypothalamus is a small region of the brain. It's located at the base of the brain, near the pituitary gland. While it's very small, the hypothalamus plays a crucial role in many important functions, including: releasing hormones, regulating body temperature.","marks":"1","difficulty":"1"},{"id":"objective>Biology>2021>18","subject":"Biology","year":"2021","type":"Objective","topic":"CONCEPT OF LIVING : SENSE ORGANS","question":"the diagram is an illustration of a type of eye defect in humans. Study it and answer the question below      The eye defect illustrated in the diagram is","images":["data:image/jpeg;base64,"],"options":{"A":"hypermetropia","B":"astigmatism","C":"presbyopia","D":"myopia"},"answer":"D","explanation":"In the diagram illustrated, eye ball is too long hence this is a case of short sightedness or myopia","marks":"1","difficulty":"2"},{"id":"objective>Biology>2021>19","subject":"Biology","year":"2021","type":"Objective","topic":"CONCEPT OF LIVING : SENSE ORGANS","question":"the diagram is an illustration of a type of eye defect in humans. Study it and answer the question below    The eye defect can be corrected by the use of","images":["data:image/jpeg;base64,"],"options":{"A":"convex lens","B":"concave lens","C":"bifocal lens","D":"cylindrical lens"},"answer":"B","explanation":"Myopia can be corrected by using concave lens eye-glasses which diverge (blend light rays outwards) parallel light rays from distant object before falling on the eyeball and thus focusing them on the retina","marks":"1","difficulty":"2"},{"id":"objective>Biology>2021>20","subject":"Biology","year":"2021","type":"Objective","topic":"CONCEPT OF LIVING : REPRODUCTION","question":"How many gametes are produced in the pollen grain of a flowing plant before fertilization ?","images":[],"options":{"A":"One","B":"two","C":"three","D":"four"},"answer":"B","explanation":"In flowering plants, each pollen grain produces two male gametes. This process is part of the double fertilization mechanism in angiosperms, where one male gamete fuses with the egg cell to form the zygote, and the other fuses with two polar nuclei to form the endosperm.","marks":"1","difficulty":"1"},{"id":"objective>Biology>2021>21","subject":"Biology","year":"2021","type":"Objective","topic":"ADAPTATION FOR SURVIVAL AND EVOLUTION : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS.","question":"Which of the following organism does not undergo incomplete metamorphosis?","images":[],"options":{"A":"locust","B":"Grasshopper","C":"Butterfly","D":"cockroach"},"answer":"C","explanation":"Butterflies undergo complete metamorphosis, which includes four stages: egg, larva (caterpillar), pupa (chrysalis), and adult. In contrast, insects like locusts, grasshoppers, and cockroaches undergo incomplete metamorphosis, which includes three stages: egg, nymph, and adult. The nymph stage resembles the adult but is smaller and lacks mature wings.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2021>22","subject":"Biology","year":"2021","type":"Objective","topic":"CONCEPT OF LIVING : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS.","question":"An enzyme reaction may begin to decline when","images":[],"options":{"A":"the optimum temperature is attained","B":"The pH of the medium is altered","C":"There is an increase in substrate concentration","D":"The atmospheric pressure is altered"},"answer":"B","explanation":"Enzymes function at specific pH, so when the pH of a medium in which an enzyme is supposed to function changes from what it normally is ot something else, the enzyme's function with decline","marks":"1","difficulty":"2"},{"id":"objective>Biology>2021>23","subject":"Biology","year":"2021","type":"Objective","topic":"BASIC ECOLOGICAL CONCEPTS : ECOSYSTEM","question":"The diagram below is an illustration of the growth of plant in water culture. After a few days, the solution turn green and the plant died. Use the informatin to answer the question below       What is the precaution should be taken to prevent the solution from turning green","images":["data:image/jpeg;base64,"],"options":{"A":"Use a non-green plant for the experiment","B":"Aerate the solution daily","C":"cover the culture vessel with opaque paper","D":"Keep cotton wool around the seedling to make it dry"},"answer":"C","explanation":"The culture solution should be covered with an opaque paper to prevent the entry of sunlight","marks":"1","difficulty":"3"},{"id":"objective>Biology>2021>24","subject":"Biology","year":"2021","type":"Objective","topic":"BASIC ECOLOGICAL CONCEPTS : ECOSYSTEM","question":"The diagram below is an illustration of the growth of plant in water culture. After a few days, the solution turn green and the plant died. Use the informatin to answer the question below     The death of the plant was likely caused by","images":["data:image/jpeg;base64,"],"options":{"A":"excess supply of nutrients to the plant","B":"inadequate supply of water to the plant","C":"Algal growth in the solution that used up the nutrient","D":"inability of the plant to make food due to lack of sunlight"},"answer":"C","explanation":"The death of the plant was due to algal growth in the solution that used up the nutrients making the plant nutrient-deficient","marks":"1","difficulty":"3"},{"id":"objective>Biology>2021>25","subject":"Biology","year":"2021","type":"Objective","topic":"PLANT AND ANIMAL NUTRITION : PLANT NUTRITION","question":"Which of the following factors is not necessary for photosynthesis?","images":[],"options":{"A":"water","B":"carbon(iv) oxide","C":"wind","D":"sunlight"},"answer":"C","explanation":"Photosynthesis is the process by which green plants and some other organisms use sunlight to synthesize foods with the aid of chlorophyll pigments. The necessary factors for photosynthesis include sunlight, water, and carbon dioxide. Wind is not a necessary factor for photosynthesis. While it can affect the rate of transpiration (which can indirectly influence photosynthesis), it is not directly involved in the photosynthesis process itself.","marks":"1","difficulty":"1"},{"id":"objective>Biology>2021>26","subject":"Biology","year":"2021","type":"Objective","topic":"PLANT AND ANIMAL NUTRITION : MODES OF NUTRITION","question":"Autotrophic nutrition is a process whereby an organism obtains food","images":[],"options":{"A":"by utilizing it stored energy","B":"by synthesizing simple substance using energy","C":"from other organism in exchange for some products","D":"in a synthesized form, from other living organism"},"answer":"B","explanation":"In autotrophic nutrition, the organism manufactures it food from simple substance using energy (from sunlight as in photosynthesis or chemical compound as in chemosynthesis)","marks":"1","difficulty":"1"},{"id":"objective>Biology>2021>27","subject":"Biology","year":"2021","type":"Objective","topic":"PLANT AND ANIMAL NUTRITION : PLANT NUTRITION","question":"The process that takes place at the light stage of photosynthesis is","images":[],"options":{"A":"splitting of water molecules to form hydrogen ions","B":"reduction of carbon (IV) oxide to form carbohydrate.","C":"formation of two molecules of Phosphoglyceric acid","D":"breaking down of ATP molecules to produce energy"},"answer":"A","explanation":"One of the processes that takes place in the light-dependent stage of photosynthesis in the photolysis of water, i.e the splitting of water molecules.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2021>28","subject":"Biology","year":"2021","type":"Objective","topic":"ADAPTATION FOR SURVIVAL AND EVOLUTION : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS.","question":"The diagram below is an illustration of the foot of an animal      The adaptation of this type of foot is that it is","images":["data:image/jpeg;base64,"],"options":{"A":"used as a bait to catch fish in water","B":"used as a paddle for swimming","C":"effective in scratching the soil for food","D":"used for killing prey in water"},"answer":"B","explanation":"Webbed feet are adapted for swimming by functioning like paddles. The webbing between the toes expands the surface area, allowing the animal to push more water with each stroke. This paddle-like action provides increased propulsion, making swimming more efficient and enabling the animal to move quickly and smoothly through the water. The webbed feet also help with steering and maneuverability, allowing for precise control while swimming.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2021>29","subject":"Biology","year":"2021","type":"Objective","topic":"PLANT AND ANIMAL NUTRITION : PLANT NUTRITION","question":"The following organism are examples of carnivorous plants except","images":[],"options":{"A":"Gloriosa","B":"venus flytrap","C":"pitcher plant","D":"utricularia"},"answer":"A","explanation":"Gloriosa is not a carnivorous plants. Carnivorous plants are plants that grow in environment/soil with low nitrogen, hence, they derive their nitrogen from insect which they trap with special modified  body parts. Examples include: pitcher, utricularia, venus  fly trap e.t.c.","marks":"1","difficulty":"1"},{"id":"objective>Biology>2021>30","subject":"Biology","year":"2021","type":"Objective","topic":"BASIC ECOLOGICAL CONCEPTS : COMMUNITY","question":"Plant and animals of an ecosystem make up a","images":[],"options":{"A":"habitat","B":"succession","C":"community","D":"population"},"answer":"C","explanation":"In an ecosystem, the plants and animals together make up a community. A community in biology refers to an interacting group of various species in a common location. For example, a forest of trees and undergrowth plants, inhabited by animals and rooted in soil containing bacteria and fungi, constitutes a biological community. A habitat, on the other hand, is the natural home or environment of an animal, plant, or other organism. Succession is a series of progressive changes in the species composition of an ecological community over time, and a population refers to all the organisms of the same group or species who live in a particular geographical area.","marks":"1","difficulty":"1"},{"id":"objective>Biology>2021>31","subject":"Biology","year":"2021","type":"Objective","topic":"ADAPTATION FOR SURVIVAL AND EVOLUTION : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS.","question":"Rabbits cannot survive in an aquatic habitat because they have","images":[],"options":{"A":"no scales","B":"no gills","C":"fore limbs","D":"lateral line"},"answer":"B","explanation":"Rabbits cannot survive in an aquatic habitat for many reason. One important reasons is that they do not use gills for respiration, hence, they will suffocate due to lack of oxygen","marks":"1","difficulty":"1"},{"id":"objective>Biology>2021>32","subject":"Biology","year":"2021","type":"Objective","topic":"BASIC ECOLOGICAL CONCEPTS : FOOD WEBS AND TROPHIC LEVELS","question":"The illustration below is a food chain   grass \u2192grasshopper\u2192domestic fowl \u2192hawk  What would happen if the population of domestic fowl decrease? The population of","images":[],"options":{"A":"grasshoppers would decrease","B":"Hawks would increase","C":"grasshoppers would increase","D":"grass available to grasshopper would increase"},"answer":"C","explanation":"The domestic fowl is directly related to the grasshopper in the food chain, when the population of domestic fowl decrease, it implies that the survival rate of th grasshopper will increase, and hence their population.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2021>33","subject":"Biology","year":"2021","type":"Objective","topic":"ADAPTATION FOR SURVIVAL AND EVOLUTION : EVOLUTION","question":"Which of the following feature is a characteristics of aquatic plants? possession of","images":[],"options":{"A":"multiple epidermis","B":"heavily lignified tissue","C":"finely divided leaves","D":"succulent stem"},"answer":"C","explanation":"Aquatic plants often have finely divided leaves to increase their surface area for maximum absorption of sunlight and gases. This is because water absorbs light, so the plants need to capture as much light energy as possible. The other options are not characteristic of aquatic plants. Multiple epidermis and heavily lignified tissue are more common in terrestrial plants, which need to retain water and support their own weight. Succulent stems are a feature of desert plants, which store water in their stems to survive in arid conditions.","marks":"1","difficulty":"1"},{"id":"objective>Biology>2021>34","subject":"Biology","year":"2021","type":"Objective","topic":"ECOLOGICAL MANAGEMENT : BIOLOGICAL ASSOCIATIONS","question":"an association between living organism in which one organism lives on and feeds at the  expense of the other organism is known as","images":[],"options":{"A":"mutualism","B":"commensalism","C":"parasitism","D":"predation"},"answer":"C","explanation":"This is known as parasitism, the organism that lives on and feeds at the expense of the other organism is the parasite, while the other organism which is expended or deprived is the host","marks":"1","difficulty":"2"},{"id":"objective>Biology>2021>35","subject":"Biology","year":"2021","type":"Objective","topic":"ECOLOGY OF POPULATION : FACTORS THAT AFFECT POPULATION","question":"When a large number of organism share limited resources, the result is","images":[],"options":{"A":"mutualism","B":"extinction","C":"commensalism","D":"competition"},"answer":"D","explanation":"When a large number of organisms share limited resources, the result is competition. This is because all the organisms are trying to use the same limited resources to survive and reproduce, leading to a struggle for survival. This is a fundamental concept in ecology known as 'competition'. None of the other options (mutualism, extinction, commensalism) accurately describe this scenario.","marks":"1","difficulty":"1"},{"id":"objective>Biology>2021>36","subject":"Biology","year":"2021","type":"Objective","topic":"MICROORGANISMS: MAN AND HEALTH : TOWARDS BETTER HEALTH","question":"Which of the following behaviours is correctly matched with the corresponding disease?","images":[],"options":{"A":"Behaviour Diseasesmoking  cigarette liver cirrhosis; lung cancer; Aids.","B":"Behaviour Diseasehaving multiple sex partners  liver cirrhosis; syphilis; Aids.","C":"Behaviour Diseaseliving near dirty gutter syphilis; lung cancer; Aids.","D":"Behaviour Diseaseeating uncooked meat  dysentery; cholera;food poisoning."},"answer":"D","explanation":"- Having multiple sexual partners increases the risk of contracting sexually transmitted infections (STIs) like syphilis and AIDS.  - Liver cirrhosis is not directly related to having multiple sexual partners, but alcohol consumption, which can increase the risk of liver cirrhosis, may be more common among people with risky sexual behavior.    The other options are not correctly matched:  Smoking cigarettes is linked to lung cancer, but not liver cirrhosis or AIDS.  Living near a dirty gutter may increase the risk of waterborne diseases like cholera or dysentery, but not lung cancer or syphilis.  Eating uncooked meat can lead to food poisoning, dysentery, or cholera, but not liver cirrhosis or syphilis.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2021>37","subject":"Biology","year":"2021","type":"Objective","topic":"CONSERVATION OF NATURAL RESOURCES : SOIL, WATER, WILDLIFE, FOREST AND MINERALS","question":"Endangered species are organism that are","images":[],"options":{"A":"likely to migrate to other favourable lands","B":"likely to disappear from the surface of the earth","C":"reproducing profusely in an area","D":"dangerous to humans and attacking other animals"},"answer":"B","explanation":"Endangered species are organisms that are at risk of becoming extinct, or disappearing from the surface of the earth. This can be due to a variety of factors such as habitat loss, climate change, or overexploitation. The other options do not accurately describe what it means for a species to be endangered.","marks":"1","difficulty":"1"},{"id":"objective>Biology>2021>38","subject":"Biology","year":"2021","type":"Objective","topic":"CONSERVATION OF NATURAL RESOURCES : WAYS OF ENSURING CONSERVATION","question":"Which of the following practices is a wildlife conservation method?","images":[],"options":{"A":"use of cover crops","B":"crop rotation","C":"mulching","D":"discouraging poaching"},"answer":"D","explanation":"Wildlife conservation methods are practices that help to protect and preserve wildlife and their habitats. Discouraging poaching is a wildlife conservation method because poaching, or the illegal hunting or capturing of wild animals, is a major threat to many species. The other options listed are agricultural practices, not wildlife conservation methods.","marks":"1","difficulty":"1"},{"id":"objective>Biology>2021>39","subject":"Biology","year":"2021","type":"Objective","topic":"CONSERVATION OF NATURAL RESOURCES : SOIL, WATER, WILDLIFE, FOREST AND MINERALS","question":"Which of the following resources cannot be conserved","images":[],"options":{"A":"forest","B":"water","C":"soil","D":"Garbage"},"answer":"D","explanation":"Garbage cannot be conserved. Conservation refers to the sustainable use and management of natural resources including wildlife, water, air, and earth deposits. While garbage can be managed and recycled, it is not a natural resource and thus cannot be conserved in the same sense as forests, water, or soil.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2021>40","subject":"Biology","year":"2021","type":"Objective","topic":"VARIATION IN POPULATION : MORPHOLOGICAL VARIATIONS","question":"the diagram below are illustration of types of comb found in domestic fowl      The type of comb show","images":["data:image/jpeg;base64,"],"options":{"A":"variation","B":"inheritance","C":"cell theory","D":"courtship behaviour"},"answer":"A","explanation":"The type of comb illustrated show variation , variation refers to the difference between individual.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2021>41","subject":"Biology","year":"2021","type":"Objective","topic":"BIOLOGY OF HEREDITY (GENETICS) : GENETIC TERMINOLOGIES","question":"the diagram below are illustration of types of comb found in domestic fowl    which factor is most likely responsible for the variation type of comb?","images":["data:image/jpeg;base64,"],"options":{"A":"environment","B":"Genetics","C":"physiology","D":"morphology"},"answer":"B","explanation":"Genetics is most likely responsible for different types of comb.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2021>42","subject":"Biology","year":"2021","type":"Objective","topic":"CONCEPT OF LIVING : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS.","question":"Which of the following statement about mitosis is not correct?","images":[],"options":{"A":"Chiasmata are found","B":"Bivalents are not formed","C":"it does lead to variation","D":"four daughter cells are produced"},"answer":"D","explanation":"Mitosis produces two diploid cells from one parent diploid cell.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2021>43","subject":"Biology","year":"2021","type":"Objective","topic":"BIOLOGY OF HEREDITY (GENETICS) : TRANSMISSION AND EXPRESSION OF CHARACTERISTICS IN ORGANISMS","question":"A mixture of blood with antigen A and blood containing antibody a will","images":[],"options":{"A":"lead to agglutination","B":"facilitate dissolution of clot","C":"have no effect on blood composition","D":"change the blood group"},"answer":"A","explanation":"When blood with antigen A is mixed with blood containing antibody a, it will lead to agglutination. Agglutination is the clumping of particles. The word agglutination comes from the Latin agglutinare (glueing to). In biology, it is a process that occurs if an antigen is mixed with its corresponding antibody. In this case, antigen A will bind with antibody a, causing the blood cells to clump together, which is known as agglutination.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2021>44","subject":"Biology","year":"2021","type":"Objective","topic":"BIOLOGY OF HEREDITY (GENETICS) : APPLICATION OF THE PRINCIPLES OF HEREDITY","question":"Plants suitable for experiment in genetics must not","images":[],"options":{"A":"produce numerous seeds within short time","B":"have small number of chromosomes","C":"have a relatively short life cycle","D":"produced one generation in a long period"},"answer":"D","explanation":"Plants suitable for experiments in genetics should not produce one generation in a long period. This is because genetic experiments often require multiple generations to observe patterns of inheritance and genetic variation. If a plant takes a long time to produce a new generation, it would slow down the research process. Therefore, ideal plants for genetic experiments should have a relatively short life cycle, produce numerous seeds within a short time, and have a small number of chromosomes for easier genetic analysis.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2021>45","subject":"Biology","year":"2021","type":"Objective","topic":"BIOLOGY OF HEREDITY (GENETICS) : GENETIC TERMINOLOGIES","question":"Which of the following statement about sickle cell anaemia is correct ?","images":[],"options":{"A":"it is caused by sex-linked genes","B":"it is more common in males than in females","C":"two sickle cell carrier parents may have a sickling child","D":"it is caused by recessive genes"},"answer":"C","explanation":"Sickle cell anemia is a genetic disorder that affects the shape of the red blood cells, causing them to become sickle-shaped. It is caused by a mutation in the HBB gene, which is not sex-linked but autosomal recessive. This means that both parents must carry the sickle cell trait for a child to potentially have the disease. Therefore, the statement 'two sickle cell carrier parents may have a sickling child' is correct.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2021>46","subject":"Biology","year":"2021","type":"Objective","topic":"BIOLOGY OF HEREDITY (GENETICS) : GENETIC TERMINOLOGIES","question":"In humans, pointed eyebrows (B) is dominant trait over smooth eyebrows (b). A student and the mother have smooth eyebrows while father has pointed eyebrows. what is the genotype of the father","images":[],"options":{"A":"BB","B":"Bb","C":"BBb","D":"BBbb"},"answer":"B","explanation":"Parameter given :  B - pointed eyebrow   b - smooth eyebrow   Student  - bb (one of these allels must be from the father)  Mother - bb  Father - pointed eyebrow  The geneotype of the father is Bb.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2021>47","subject":"Biology","year":"2021","type":"Objective","topic":"BIOLOGY OF HEREDITY (GENETICS) : GENETIC TERMINOLOGIES","question":"A woman with Rhesus negative blood group was advised not marry a man with rhesus positive blood group because","images":[],"options":{"A":"it hinder her from having blood transfusion from her husband","B":"it will result in sickness and probably death of the offspring","C":"her children may all resemble her husband","D":"it may affect her child bearing ability"},"answer":"B","explanation":"A woman with Rhesus negative blood group marrying a man with Rhesus positive blood group can lead to a condition called Rhesus disease in their offspring. This happens when the mother's body produces antibodies against the Rhesus positive blood of the baby. This can lead to severe illness and even death of the baby.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2021>48","subject":"Biology","year":"2021","type":"Objective","topic":"ADAPTATION FOR SURVIVAL AND EVOLUTION : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS.","question":"Which of the following organisms exhibits division of labour","images":[],"options":{"A":"butterfly","B":"cockroach","C":"termite","D":"housefly"},"answer":"C","explanation":"Termites are social insects which exhibit labour division . The names of different castes of termites nest are :  - workers  - Soliders  - queen   - king  - winged reproductive (alates)","marks":"1","difficulty":"2"},{"id":"objective>Biology>2021>49","subject":"Biology","year":"2021","type":"Objective","topic":"ADAPTATION FOR SURVIVAL AND EVOLUTION : EVOLUTION","question":"Natural selection arises as a result of","images":[],"options":{"A":"gene mutation","B":"change of habitat","C":"reduction in population","D":"climate change"},"answer":"A","explanation":"Natural selection arises as a result of gene mutation . Mutation provides raw material for organic evolution through natural selection of new species.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2021>50","subject":"Biology","year":"2021","type":"Objective","topic":"ADAPTATION FOR SURVIVAL AND EVOLUTION : EVOLUTION","question":"Which of the following statement is not Lamarck's postulate on evolution ?","images":[],"options":{"A":"Great changes in the environment result in corresponding changes in species","B":"frequently used organs become well developed while the ones not used becomes vestigial","C":"well developed acquired characters are inheritable","D":"survivors  in a competitive community must have inherited useful traits."},"answer":"D","explanation":"The statement 'survivors in a competitive community must have inherited useful traits' is not a postulate of Lamarck's theory of evolution. This statement is more aligned with Darwin's theory of natural selection, which posits that individuals with advantageous traits are more likely to survive and reproduce. Lamarck's theory, on the other hand, proposed that an organism can change during its lifetime in response to its environment, and those changes are inheritable.","marks":"1","difficulty":"3"}];